import type {
  Element,
  ModelDelta,
  PerspectiveId,
  Snapshot,
  Violation,
  WorkspaceLayoutPreset,
} from '@bim-ai/core';

import type { WallLocationLine } from '../tools/toolGrammar';
import type { PlanPresentationPreset } from '../plan/symbology';
import type {
  PlanProjectionPrimitivesV1Wire,
  PlanCategoryGraphicHintsV0Wire,
  PlanRoomColorLegendRow,
  RoomProgrammeLegendEvidenceV0,
} from '../plan/planProjectionWire';
import type { LevelElevationPropagationEvidenceV0 } from '../workspace/levelDatumPropagationReadout';

export type PlanRoomSchemeWireReadout = {
  roomColorLegendRows: PlanRoomColorLegendRow[];
  programmeLegendEvidence: RoomProgrammeLegendEvidenceV0 | null;
  planCategoryGraphicHintsV0?: PlanCategoryGraphicHintsV0Wire | null;
};

export type ViewerMode = 'plan_canvas' | 'orbit_3d';

export type PlanTool =
  | 'select'
  | 'wall'
  | 'floor'
  | 'door'
  | 'window'
  | 'room'
  | 'room_rectangle'
  | 'grid'
  | 'dimension'
  | 'align'
  | 'split'
  | 'trim';

export type PresencePeers = Record<
  string,
  {
    peerId?: string;
    userId?: string;
    name?: string;
    color?: string;
    cursorMm?: { xMm: number; yMm: number };
    selectionId?: string;
    viewer?: string;
  }
>;

export type UxComment = {
  id: string;
  userDisplay: string;
  body: string;
  elementId?: string | null;
  levelId?: string | null;
  anchorXMm?: number | null;
  anchorYMm?: number | null;
  resolved: boolean;
  createdAt?: string;
};

export type ActivityEvent = {
  id: number;
  userId: string;
  revisionAfter: number;
  createdAt: string;
  commandTypes: string[];
};

export type StoreState = {
  modelId?: string;
  revision: number;
  elementsById: Record<string, Element>;
  violations: Violation[];
  selectedId?: string;
  viewerMode: ViewerMode;
  planTool: PlanTool;
  activeLevelId?: string;
  planPresentationPreset: PlanPresentationPreset;
  activePlanViewId?: string;
  /** Saved 3D viewpoint whose clip/layer tweaks should persist via `updateElementProperty`. */
  activeViewpointId?: string;
  /** When set, plan canvas prefers server `planProjectionWire_v1.primitives` (WP-C02/C03). */
  planProjectionPrimitives: PlanProjectionPrimitivesV1Wire | null;
  /** Last plan wire legend + programme digest readout for workbench panels (Prompt-3 room scheme). */
  planRoomSchemeWireReadout: PlanRoomSchemeWireReadout | null;
  /** Active Schedules tab row count for browser rendering budget readout (Prompt-8). */
  scheduleBudgetHydration: { tab: string; rowCount: number } | null;
  /** Latest server `levelElevationPropagationEvidence_v0` after apply (Prompt-1). */
  lastLevelElevationPropagationEvidence: LevelElevationPropagationEvidenceV0 | null;
  viewerClipElevMm: number | null;
  /** Optional lower bound — clips geometry *below* this world Y (mm) for a reproducible slab cut. */
  viewerClipFloorElevMm: number | null;
  /** When true for a semantic kind (`wall`, `roof`, …), that category is hidden in 3D. */
  viewerCategoryHidden: Record<string, boolean>;
  wallLocationLine: WallLocationLine;
  floorBoundaryOffsetMm: number;
  orthoSnapHold: boolean;
  userId: string;
  userDisplayName: string;
  peerId: string;
  presencePeers: PresencePeers;
  comments: UxComment[];
  activityEvents: ActivityEvent[];
  buildingPreset: string;
  planHudMm?: { xMm: number; yMm: number };
  workspaceLayoutPreset: WorkspaceLayoutPreset;
  perspectiveId: PerspectiveId;

  /** Bump to push a saved orbit viewpoint camera into Viewport three.js rig (WP-E02/E03). */
  orbitCameraNonce: number;
  /** Optional camera pose in model mm conventions (plan x/zMm as world-up). */
  orbitCameraPoseMm: {
    position: { xMm: number; yMm: number; zMm: number };
    target: { xMm: number; yMm: number; zMm: number };
    up: { xMm: number; yMm: number; zMm: number };
  } | null;

  hydrateFromSnapshot: (snap: Snapshot) => void;
  applyDelta: (d: ModelDelta) => void;
  select: (id?: string) => void;
  setViewerMode: (m: ViewerMode) => void;
  setPlanTool: (t: PlanTool) => void;
  setActiveLevelId: (id: string | undefined) => void;
  setWallLocationLine: (loc: WallLocationLine) => void;
  setFloorBoundaryOffsetMm: (mm: number) => void;
  setOrthoSnapHold: (v: boolean) => void;
  setPresencePeers: (peers: PresencePeers) => void;
  setComments: (c: UxComment[]) => void;
  mergeComment: (c: UxComment) => void;
  setBuildingPreset: (preset: string) => void;
  setPlanHud: (mm?: { xMm: number; yMm: number }) => void;
  setWorkspaceLayoutPreset: (p: WorkspaceLayoutPreset) => void;
  setPerspectiveId: (p: PerspectiveId) => void;
  setPlanPresentationPreset: (p: PlanPresentationPreset) => void;

  activatePlanView: (planViewElementId: string | undefined) => void;
  setActiveViewpointId: (viewpointElementId?: string) => void;
  setViewerClipElevMm: (mm: number | null) => void;
  setViewerClipFloorElevMm: (mm: number | null) => void;
  setPlanProjectionPrimitives: (p: PlanProjectionPrimitivesV1Wire | null) => void;
  setPlanRoomSchemeWireReadout: (readout: PlanRoomSchemeWireReadout | null) => void;
  setScheduleBudgetHydration: (v: { tab: string; rowCount: number } | null) => void;
  toggleViewerCategoryHidden: (semanticKind: string) => void;
  /** Apply saved 3D viewpoint clip planes + semantic category hides (WP-E02/E03). */
  applyOrbitViewpointPreset: (opts: {
    capElevMm?: number | null;
    floorElevMm?: number | null;
    hideSemanticKinds?: string[];
  }) => void;
  /** Feed Viewport orbital camera rig from element camera mm payload. */
  setOrbitCameraFromViewpointMm: (opts: {
    position: { xMm: number; yMm: number; zMm: number };
    target: { xMm: number; yMm: number; zMm: number };
    up: { xMm: number; yMm: number; zMm: number };
  }) => void;

  setActivity: (e: ActivityEvent[]) => void;
  setIdentity: (userId: string, display: string, peerId: string) => void;
};

import { describe, expect, it } from 'vitest';

import {
  doorRowsFromServer,
  flattenSchedulePayloadRows,
  fmtRoomScheduleOptM2,
  formatScheduleCell,
  levelFilterFieldForTab,
  registryScheduleTab,
  roomRowsFromServer,
  scheduleGroupingKeyChoices,
  scheduleSortKeyChoices,
  tabToPresetCategory,
  winRowsFromServer,
} from './scheduleUtils';

describe('formatScheduleCell', () => {
  it('formats null as em-dash', () => expect(formatScheduleCell(null)).toBe('—'));
  it('formats undefined as em-dash', () => expect(formatScheduleCell(undefined)).toBe('—'));
  it('formats empty string as em-dash', () => expect(formatScheduleCell('')).toBe('—'));
  it('formats integer without decimals', () => expect(formatScheduleCell(42)).toBe('42'));
  it('formats float to 3 decimal places', () => expect(formatScheduleCell(1.5)).toBe('1.500'));
  it('formats zero as 0', () => expect(formatScheduleCell(0)).toBe('0'));
  it('formats strings as-is', () => expect(formatScheduleCell('hello')).toBe('hello'));
});

describe('fmtRoomScheduleOptM2', () => {
  it('formats null as em-dash', () => expect(fmtRoomScheduleOptM2(null)).toBe('—'));
  it('formats undefined as em-dash', () => expect(fmtRoomScheduleOptM2(undefined)).toBe('—'));
  it('formats NaN as em-dash', () => expect(fmtRoomScheduleOptM2(NaN)).toBe('—'));
  it('formats a number to 3 decimal places', () =>
    expect(fmtRoomScheduleOptM2(25.5)).toBe('25.500'));
});

describe('flattenSchedulePayloadRows', () => {
  it('returns flat rows array when present', () => {
    const data = { rows: [{ id: 'a' }, { id: 'b' }] };
    expect(flattenSchedulePayloadRows(data)).toEqual([{ id: 'a' }, { id: 'b' }]);
  });

  it('flattens grouped sections when rows absent', () => {
    const data = {
      groupedSections: {
        'Level 1': [{ id: 'a' }],
        'Level 2': [{ id: 'b' }, { id: 'c' }],
      },
    };
    const result = flattenSchedulePayloadRows(data);
    expect(result).toHaveLength(3);
  });

  it('prefers flat rows over groupedSections', () => {
    const data = {
      rows: [{ id: 'a' }],
      groupedSections: { g: [{ id: 'b' }] },
    };
    expect(flattenSchedulePayloadRows(data)).toEqual([{ id: 'a' }]);
  });

  it('returns empty array when data has neither', () => {
    expect(flattenSchedulePayloadRows({})).toEqual([]);
  });
});

describe('levelFilterFieldForTab', () => {
  it('returns levelId for rooms', () => expect(levelFilterFieldForTab('rooms')).toBe('levelId'));
  it('returns levelId for doors', () => expect(levelFilterFieldForTab('doors')).toBe('levelId'));
  it('returns levelId for windows', () =>
    expect(levelFilterFieldForTab('windows')).toBe('levelId'));
  it('returns levelId for floors', () => expect(levelFilterFieldForTab('floors')).toBe('levelId'));
  it('returns levelId for plans', () => expect(levelFilterFieldForTab('plans')).toBe('levelId'));
  it('returns levelId for assemblies', () =>
    expect(levelFilterFieldForTab('assemblies')).toBe('levelId'));
  it('returns referenceLevelId for roofs', () =>
    expect(levelFilterFieldForTab('roofs')).toBe('referenceLevelId'));
  it('returns baseLevelId for stairs', () =>
    expect(levelFilterFieldForTab('stairs')).toBe('baseLevelId'));
  it('returns null for sheets', () => expect(levelFilterFieldForTab('sheets')).toBeNull());
});

describe('scheduleSortKeyChoices', () => {
  const ALL_TABS = [
    'rooms',
    'doors',
    'windows',
    'floors',
    'roofs',
    'stairs',
    'plans',
    'sheets',
    'assemblies',
  ] as const;

  it('returns non-empty array for every tab', () => {
    for (const tab of ALL_TABS) {
      expect(scheduleSortKeyChoices(tab).length).toBeGreaterThan(0);
    }
  });

  it('includes name in every tab', () => {
    for (const tab of ALL_TABS) {
      expect(scheduleSortKeyChoices(tab)).toContain('name');
    }
  });

  it('doors include widthMm', () => expect(scheduleSortKeyChoices('doors')).toContain('widthMm'));
  it('windows include heightMm', () =>
    expect(scheduleSortKeyChoices('windows')).toContain('heightMm'));
  it('rooms include areaM2', () => expect(scheduleSortKeyChoices('rooms')).toContain('areaM2'));
});

describe('scheduleGroupingKeyChoices', () => {
  it('returns levelId grouping for rooms', () => {
    expect(scheduleGroupingKeyChoices('rooms')).toContain('levelId');
  });

  it('returns levelId and familyTypeId for doors', () => {
    const keys = scheduleGroupingKeyChoices('doors');
    expect(keys).toContain('levelId');
    expect(keys).toContain('familyTypeId');
  });

  it('returns non-empty array for every tab', () => {
    const tabs = [
      'rooms',
      'doors',
      'windows',
      'floors',
      'roofs',
      'stairs',
      'plans',
      'sheets',
      'assemblies',
    ] as const;
    for (const tab of tabs) {
      expect(scheduleGroupingKeyChoices(tab).length).toBeGreaterThan(0);
    }
  });
});

describe('tabToPresetCategory', () => {
  it('maps rooms to room', () => expect(tabToPresetCategory('rooms')).toBe('room'));
  it('maps doors to door', () => expect(tabToPresetCategory('doors')).toBe('door'));
  it('maps windows to window', () => expect(tabToPresetCategory('windows')).toBe('window'));
  it('maps assemblies to material_assembly', () =>
    expect(tabToPresetCategory('assemblies')).toBe('material_assembly'));
  it('returns null for floors', () => expect(tabToPresetCategory('floors')).toBeNull());
  it('returns null for roofs', () => expect(tabToPresetCategory('roofs')).toBeNull());
  it('returns null for stairs', () => expect(tabToPresetCategory('stairs')).toBeNull());
  it('returns null for sheets', () => expect(tabToPresetCategory('sheets')).toBeNull());
  it('returns null for plans', () => expect(tabToPresetCategory('plans')).toBeNull());
});

describe('registryScheduleTab', () => {
  it('returns true for registry tabs', () => {
    for (const tab of ['floors', 'roofs', 'stairs', 'plans', 'sheets', 'assemblies'] as const) {
      expect(registryScheduleTab(tab)).toBe(true);
    }
  });

