505	      const pwRaw = r.playwrightSuggestedFilenames;
506	      const pw = pwRaw && typeof pwRaw === 'object' ? (pwRaw as Record<string, unknown>) : {};
507	      const corrRaw = r.correlation;
508	      const corr =
509	        corrRaw && typeof corrRaw === 'object' ? (corrRaw as Record<string, unknown>) : {};
510	      return {
511	        viewpointId: String(r.viewpointId ?? r.viewpoint_id ?? ''),
512	        viewpointName:
513	          typeof r.viewpointName === 'string'
514	            ? r.viewpointName
515	            : typeof r.viewpoint_name === 'string'
516	              ? r.viewpoint_name
517	              : undefined,
518	        pngViewport: typeof pw.pngViewport === 'string' ? pw.pngViewport : undefined,
519	        bundleJson:
520	          typeof corr.suggestedEvidenceBundleEvidencePackageJson === 'string'
521	            ? corr.suggestedEvidenceBundleEvidencePackageJson
522	            : typeof corr.suggested_evidence_bundle_evidence_package_json === 'string'
523	              ? corr.suggested_evidence_bundle_evidence_package_json
524	              : undefined,
525	      };
526	    });
527	
528	    const dpv = payload.deterministicPlanViewEvidence ?? payload.deterministic_plan_view_evidence;
529	    const prowsRaw = Array.isArray(dpv) ? dpv : [];
530	    const planViewRows = prowsRaw.map((row) => {
531	      const r = row as Record<string, unknown>;
532	      const pwRaw = r.playwrightSuggestedFilenames;
533	      const pw = pwRaw && typeof pwRaw === 'object' ? (pwRaw as Record<string, unknown>) : {};
534	      const corrRaw = r.correlation;
535	      const corr =
536	        corrRaw && typeof corrRaw === 'object' ? (corrRaw as Record<string, unknown>) : {};
537	      return {
538	        planViewId: String(r.planViewId ?? r.plan_view_id ?? ''),
539	        name: typeof r.name === 'string' ? r.name : undefined,
540	        levelId:
541	          typeof r.levelId === 'string'
542	            ? r.levelId
543	            : typeof r.level_id === 'string'
544	              ? r.level_id
545	              : undefined,
546	        planPresentation:
547	          typeof r.planPresentation === 'string'
548	            ? r.planPresentation
549	            : typeof r.plan_presentation === 'string'
550	              ? r.plan_presentation
551	              : undefined,
552	        pngPlanCanvas: typeof pw.pngPlanCanvas === 'string' ? pw.pngPlanCanvas : undefined,
553	        bundleJson:
554	          typeof corr.suggestedEvidenceBundleEvidencePackageJson === 'string'
555	            ? corr.suggestedEvidenceBundleEvidencePackageJson
556	            : typeof corr.suggested_evidence_bundle_evidence_package_json === 'string'
557	              ? corr.suggested_evidence_bundle_evidence_package_json
558	              : undefined,
559	      };
560	    });
561	
562	    const dsc =
563	      payload.deterministicSectionCutEvidence ?? payload.deterministic_section_cut_evidence;
564	    const secrowsRaw = Array.isArray(dsc) ? dsc : [];
565	    const sectionCutRows = secrowsRaw.map((row) => {
566	      const r = row as Record<string, unknown>;
567	      const pwRaw = r.playwrightSuggestedFilenames;
568	      const pw = pwRaw && typeof pwRaw === 'object' ? (pwRaw as Record<string, unknown>) : {};
569	      const corrRaw = r.correlation;
570	      const corr =
571	        corrRaw && typeof corrRaw === 'object' ? (corrRaw as Record<string, unknown>) : {};
572	      return {
573	        sectionCutId: String(r.sectionCutId ?? r.section_cut_id ?? ''),
574	        name: typeof r.name === 'string' ? r.name : undefined,
575	        projectionWireHref:
576	          typeof r.projectionWireHref === 'string'
577	            ? r.projectionWireHref
578	            : typeof r.projection_wire_href === 'string'
579	              ? r.projection_wire_href
580	              : undefined,
581	        pngSectionViewport:
582	          typeof pw.pngSectionViewport === 'string' ? pw.pngSectionViewport : undefined,
583	        bundleJson:
584	          typeof corr.suggestedEvidenceBundleEvidencePackageJson === 'string'
585	            ? corr.suggestedEvidenceBundleEvidencePackageJson
586	            : typeof corr.suggested_evidence_bundle_evidence_package_json === 'string'
587	              ? corr.suggested_evidence_bundle_evidence_package_json
588	              : undefined,
589	      };
590	    });
591	
592	    const reviewActionsParsed = parseAgentReviewActionsV1(
593	      payload.agentReviewActions_v1 ?? payload.agent_review_actions_v1,
594	    );
595	    const reviewActions = [
596	      ...reviewActionsParsed.filter((a) => a.kind === 'remediateEvidenceDiffIngest'),
597	      ...reviewActionsParsed.filter((a) => a.kind !== 'remediateEvidenceDiffIngest'),
598	    ];
599	
600	    const mismatchNotes: string[] = [];
601	
602	    const noteCorrelationDigest = (corr: Record<string, unknown>, label: string, id: string) => {
603	      const rowSha =
604	        typeof corr.semanticDigestSha256 === 'string' ? corr.semanticDigestSha256 : null;
605	      if (dig && rowSha && rowSha !== dig) {
