615	      const cRaw = rowsRaw[i] as Record<string, unknown>;
616	      const corrRaw = cRaw?.correlation;
617	      const corr =
618	        corrRaw && typeof corrRaw === 'object' ? (corrRaw as Record<string, unknown>) : {};
619	      const rowPrefix =
620	        typeof corr.semanticDigestPrefix16 === 'string' ? corr.semanticDigestPrefix16 : null;
621	      if (prefix && rowPrefix && rowPrefix !== prefix) {
622	        mismatchNotes.push(
623	          `Sheet ${sr.sheetId}: correlation semanticDigestPrefix16 (${rowPrefix}) ≠ package (${prefix}).`,
624	        );
625	      }
