642	        corrRaw && typeof corrRaw === 'object' ? (corrRaw as Record<string, unknown>) : {};
643	      const rowPrefix =
644	        typeof corr.semanticDigestPrefix16 === 'string' ? corr.semanticDigestPrefix16 : null;
645	      if (prefix && rowPrefix && rowPrefix !== prefix) {
