656	      const cRaw = prowsRaw[i] as Record<string, unknown>;
657	      const corrRaw = cRaw?.correlation;
658	      const corr =
659	        corrRaw && typeof corrRaw === 'object' ? (corrRaw as Record<string, unknown>) : {};
660	      const rowPrefix =
661	        typeof corr.semanticDigestPrefix16 === 'string' ? corr.semanticDigestPrefix16 : null;
662	      if (prefix && rowPrefix && rowPrefix !== prefix) {
663	        mismatchNotes.push(
664	          `Plan ${pr.planViewId}: correlation semanticDigestPrefix16 (${rowPrefix}) ≠ package (${prefix}).`,
665	        );
666	      }
