669	
670	    for (let i = 0; i < secrowsRaw.length; i++) {
671	      const sec = sectionCutRows[i];
672	      if (!sec?.sectionCutId) continue;
673	      const cRaw = secrowsRaw[i] as Record<string, unknown>;
674	      const corrRaw = cRaw?.correlation;
675	      const corr =
676	        corrRaw && typeof corrRaw === 'object' ? (corrRaw as Record<string, unknown>) : {};
677	      const rowPrefix =
678	        typeof corr.semanticDigestPrefix16 === 'string' ? corr.semanticDigestPrefix16 : null;
679	      if (prefix && rowPrefix && rowPrefix !== prefix) {
680	        mismatchNotes.push(
681	          `Section ${sec.sectionCutId}: correlation semanticDigestPrefix16 (${rowPrefix}) ≠ package (${prefix}).`,
682	        );
683	      }
684	      noteCorrelationDigest(corr, 'Section', sec.sectionCutId);
685	    }
686	
687	    for (const sr of sheetRows) {
688	      if (!sr.sheetId) continue;
689	      if (!sr.pngViewport && !sr.pngFullSheet) {
690	        mismatchNotes.push(
691	          `Sheet ${sr.sheetId}: missing Playwright PNG hints in deterministic sheet evidence row — rerun evidence-baselines or refresh manifest.`,
692	        );
693	      }
694	    }
695	    for (const vr of view3dRows) {
696	      if (!vr.viewpointId) continue;
697	      if (!vr.pngViewport) {
698	        mismatchNotes.push(
699	          `Viewpoint ${vr.viewpointId}: missing pngViewport hint — regenerate deterministic 3D evidence.`,
700	        );
701	      }
702	    }
703	    for (const pr of planViewRows) {
704	      if (!pr.planViewId) continue;
705	      if (!pr.pngPlanCanvas) {
