707	          `Plan view ${pr.planViewId}: missing pngPlanCanvas hint — refresh evidence-package or extend server manifest.`,
708	        );
709	      }
710	    }
711	    for (const sec of sectionCutRows) {
712	      if (!sec.sectionCutId) continue;
713	      if (!sec.pngSectionViewport) {
714	        mismatchNotes.push(
715	          `Section cut ${sec.sectionCutId}: missing pngSectionViewport hint — refresh evidence-package or extend server manifest.`,
716	        );
717	      }
718	    }
719	
720	    let evidenceFreshness: EvidenceArtifactSummary['evidenceFreshness'] = null;
721	    if (closureReview) {
