730	    const regenRaw =
731	      typeof evidenceTxt === 'string'
732	        ? (() => {
733	            try {
734	              return JSON.parse(evidenceTxt) as Record<string, unknown>;
735	            } catch {
736	              return null;
737	            }
738	          })()
