746	          regenerationGuidance = actionsRaw
747	            .filter((a): a is Record<string, unknown> => typeof a === 'object' && a !== null)
748	            .map((a) => ({
749	              priority: typeof a.priority === 'string' ? a.priority : 'low',
750	              artifactKey: typeof a.artifactKey === 'string' ? a.artifactKey : '',
751	              reason: typeof a.reason === 'string' ? a.reason : '',
752	              suggestedCommand: typeof a.suggestedCommand === 'string' ? a.suggestedCommand : '',
753	            }))
754	            .filter((a) => a.artifactKey.length > 0);
755	        }
756	      }
757	    }
758	
759	    return {
760	      semanticDigestPrefix16: prefix,
761	      semanticDigestSha256Tail: shaTail,
762	      semanticDigestSha256Full: dig,
763	      modelRevision:
764	        modelRevision !== null && Number.isFinite(modelRevision) ? modelRevision : null,
765	      sheetRows,
766	      view3dRows,
767	      planViewRows,
768	      sectionCutRows,
769	      closureHints,
770	      closureReview,
771	      lifecycleSignal,
772	      agentFollowThrough,
773	      screenshotSlotGaps,
774	      suggestedBasenameHint: basename,
775	      mismatchNotes,
776	      diffFixLoop,
777	      performanceGate,
778	      reviewActions,
779	      artifactUploadManifestReadout,
780	      baselineLifecycleReadout,
781	      consistencyClosure,
782	      prdCloseoutCrossCorrelation,
783	      evidenceFreshness,
784	      regenerationGuidance,
785	    };
786	  } catch {
787	    return {
788	      semanticDigestPrefix16: null,
789	      semanticDigestSha256Tail: null,
790	      semanticDigestSha256Full: null,
791	      modelRevision: null,
792	      sheetRows: [],
793	      view3dRows: [],
794	      planViewRows: [],
795	      sectionCutRows: [],
796	      closureHints: null,
797	      closureReview: null,
798	      lifecycleSignal: null,
799	      agentFollowThrough: null,
800	      screenshotSlotGaps: null,
801	      suggestedBasenameHint: null,
802	      mismatchNotes: ['Could not parse evidence JSON for artifact summary.'],
803	      diffFixLoop: null,
804	      performanceGate: null,
